import{_ as l,o as e,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"丹溪心法","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/04-丹溪心法（朱震亨）.md","filePath":"tcm-data/03-宋金元/04-丹溪心法（朱震亨）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/03-宋金元/04-丹溪心法（朱震亨）.md"};function n(i,t,s,d,g,h){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="丹溪心法" tabindex="-1">丹溪心法 <a class="header-anchor" href="#丹溪心法" aria-label="Permalink to &quot;丹溪心法&quot;">​</a></h1><blockquote><p>朱震亨（1281-1358年），浙江义乌人 金元四大家之末，&quot;滋阴派&quot;创始人 代表作：《格致余论》《丹溪心法》《局方发挥》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字彦修，人称丹溪先生</li><li><strong>生平</strong>：30岁开始学医，师从罗知悌（刘完素再传弟子），刻苦攻读《内经》等经典</li><li><strong>学术地位</strong>：金元四大家之一，&quot;<strong>阳常有余，阴常不足</strong>&quot;</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-阳常有余-阴常不足" tabindex="-1">1. 阳常有余，阴常不足 <a class="header-anchor" href="#_1-阳常有余-阴常不足" aria-label="Permalink to &quot;1. 阳常有余，阴常不足&quot;">​</a></h3><blockquote><p><strong>「人受天地之气以生，天之阳气为气，地之阴气为血。故气常有余，血常不足。」</strong></p></blockquote><ul><li><strong>生理上</strong>：人体&quot;阳动阴静&quot;，阳气易动而阴液难成</li><li><strong>病理上</strong>：人一生处于&quot;阴不足&quot;的状态，尤其是肝肾之阴</li><li><strong>治疗上</strong>：<strong>滋阴降火</strong>是重要方法</li></ul><h3 id="_2-相火论" tabindex="-1">2. 相火论 <a class="header-anchor" href="#_2-相火论" aria-label="Permalink to &quot;2. 相火论&quot;">​</a></h3><blockquote><p><strong>「相火者，天火也。龙雷之火也。」</strong></p></blockquote><ul><li>相火寄于肝肾，正常时&quot;藏而不露&quot;，维持人体生机</li><li>相火妄动 → 煎熬真阴 → 阴虚火旺</li></ul><h3 id="_3-泻南方补北方" tabindex="-1">3. 泻南方补北方 <a class="header-anchor" href="#_3-泻南方补北方" aria-label="Permalink to &quot;3. 泻南方补北方&quot;">​</a></h3><blockquote><p><strong>「泻南方则肺金不伤，补北方则心火自降。」</strong></p></blockquote><ul><li>南方=心（火）→ 泻南方=清心火</li><li>北方=肾（水）→ 补北方=滋肾水</li><li><strong>&quot;泻南补北&quot;</strong> = 水火既济</li></ul><h3 id="_4-气血痰郁为病" tabindex="-1">4. 气血痰郁为病 <a class="header-anchor" href="#_4-气血痰郁为病" aria-label="Permalink to &quot;4. 气血痰郁为病&quot;">​</a></h3><p>朱震亨认为人身诸病多因<strong>气血痰郁</strong>：</p><ul><li>气病 → 四君子汤</li><li>血病 → 四物汤</li><li>痰病 → 二陈汤</li><li>郁病 → 越鞠丸</li></ul><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大补阴丸</strong></td><td style="text-align:left;">熟地、龟板、黄柏、知母、猪脊髓</td><td style="text-align:left;">阴虚火旺</td><td style="text-align:left;">更年期潮热、肺结核</td></tr><tr><td style="text-align:left;"><strong>越鞠丸</strong></td><td style="text-align:left;">苍术、香附、川芎、神曲、栀子</td><td style="text-align:left;">六郁（气郁为主）</td><td style="text-align:left;">抑郁症、胃胀</td></tr><tr><td style="text-align:left;"><strong>二陈汤</strong></td><td style="text-align:left;">半夏、陈皮、茯苓、甘草</td><td style="text-align:left;">湿痰咳嗽</td><td style="text-align:left;">慢支、痰多</td></tr><tr><td style="text-align:left;"><strong>左金丸</strong></td><td style="text-align:left;">黄连、吴茱萸（6:1）</td><td style="text-align:left;">肝火犯胃</td><td style="text-align:left;">胃酸过多</td></tr><tr><td style="text-align:left;"><strong>虎潜丸</strong></td><td style="text-align:left;">黄柏、龟板、知母、熟地、陈皮、白芍、锁阳、虎骨、干姜</td><td style="text-align:left;">肝肾阴虚，筋骨痿软</td><td style="text-align:left;">骨质疏松</td></tr><tr><td style="text-align:left;"><strong>玉屏风散</strong></td><td style="text-align:left;">黄芪、白术、防风</td><td style="text-align:left;">表虚自汗</td><td style="text-align:left;">反复感冒</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><blockquote><p><strong>「阳常有余，阴常不足。」</strong></p></blockquote><blockquote><p><strong>「相火者，天火也。龙雷之火也。」</strong></p></blockquote><blockquote><p><strong>「气血冲和，万病不生；一有怫郁，诸病生焉。」</strong></p></blockquote><blockquote><p><strong>「体虚不受补，乃体中有邪也。」</strong></p></blockquote><blockquote><p><strong>「湿热相火，为病最多。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="黄元御与朱震亨" tabindex="-1">黄元御与朱震亨 <a class="header-anchor" href="#黄元御与朱震亨" aria-label="Permalink to &quot;黄元御与朱震亨&quot;">​</a></h3><p>两人对<strong>相火</strong>的理解有本质不同：</p><ul><li><strong>朱震亨</strong>：相火是&quot;贼&quot;，妄动致病，需滋阴降火</li><li><strong>黄元御</strong>：相火是生命之火，不降的原因是中土湿寒、肾水寒凝，需要温阳引火归原</li></ul><p><strong>该男性患者的证候更符合黄元御的判断</strong>——口渴不贪凉、腰腹凉、前胸出汗多 → 这是阳虚相火不降，而非阴虚相火妄动。</p><h3 id="现代应用" tabindex="-1">现代应用 <a class="header-anchor" href="#现代应用" aria-label="Permalink to &quot;现代应用&quot;">​</a></h3><ul><li>大补阴丸 → 更年期综合征</li><li>越鞠丸 → 抑郁症、焦虑症</li><li>玉屏风散 → 反复感冒、过敏性鼻炎</li></ul><hr><p><em>本条目为精简框架版。可与黄元御的相火理论对比分析，以及朱震亨的滋阴法与李东垣的补土法在临床上的异同。</em></p>',39)])])}const q=l(r,[["render",n]]);export{c as __pageData,q as default};
